<?php
 namespace FilesManager; class Validator { public static function validatePath(string $path, string $basePath): string|false { $path = trim($path); $path = str_replace(['\\', '//'], '/', $path); $path = preg_replace('#/+#', '/', $path); if (strpos($path, '..') !== false) { return false; } $realPath = realpath($basePath . '/' . $path); $realBase = realpath($basePath); if ($realPath === false || strpos($realPath, $realBase) !== 0) { return false; } return $realPath; } public static function validateFileName(string $name): bool { $invalidChars = ['<', '>', ':', '"', '/', '\\', '|', '?', '*']; if (strlen($name) === 0 || strlen($name) > 255) { return false; } foreach ($invalidChars as $char) { if (strpos($name, $char) !== false) { return false; } } if ($name === '.' || $name === '..') { return false; } return true; } public static function validateExtension(string $filename, array $allowedExtensions = []): bool { if (empty($allowedExtensions)) { return true; } $ext = strtolower(pathinfo($filename, PATHINFO_EXTENSION)); return in_array($ext, $allowedExtensions, true); } public static function validateMimeType(string $filePath, array $allowedMimes = []): bool { if (empty($allowedMimes)) { return true; } if (!file_exists($filePath)) { return false; } $finfo = finfo_open(FILEINFO_MIME_TYPE); $mimeType = finfo_file($finfo, $filePath); finfo_close($finfo); return in_array($mimeType, $allowedMimes, true); } public static function validateFileSize(int $fileSize, int $maxSize = 0): bool { if ($maxSize === 0) { return true; } return $fileSize <= $maxSize; } public static function sanitizeString(string $input): string { return htmlspecialchars($input, ENT_QUOTES, 'UTF-8'); } public static function validateCsrfToken(string $token, string $sessionToken): bool { return hash_equals($sessionToken, $token); } public static function generateCsrfToken(): string { return bin2hex(random_bytes(32)); } } 